namespace sv_94fe76272eb645ad80248a942ee4e504.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public sealed record StatusUpdate(DateTimeOffset Timestamp, string Description);

using sv_94fe76272eb645ad80248a942ee4e504.Client.Services;

namespace sv_94fe76272eb645ad80248a942ee4e504.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            "PKG-001",
            "In Transit",
            "Chicago, IL",
            new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 23, 8, 0, 0, TimeSpan.Zero), "Package picked up"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.Zero), "In transit to destination"),
            ]),
        ["PKG-002"] = new ShipmentDetails(
            "PKG-002",
            "Delivered",
            "New York, NY",
            new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), "Package picked up"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 11, 0, 0, TimeSpan.Zero), "Arrived at regional hub"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 22, 16, 45, 0, TimeSpan.Zero), "Out for delivery"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 22, 18, 10, 0, TimeSpan.Zero), "Delivered"),
            ]),
        ["PKG-003"] = new ShipmentDetails(
            "PKG-003",
            "Processing",
            "Los Angeles, CA",
            new DateTimeOffset(2026, 5, 30, 20, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.Zero), "Order received, preparing shipment"),
            ]),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_94fe76272eb645ad80248a942ee4e504.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<TrackShipment> Logger

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-message">
        <p>@_errorMessage</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.Updates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; @update.Description
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task Retry()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

