2. @using sv_94fe76272eb645ad80248a942ee4e504.Client.Services
3. @rendermode InteractiveAuto
4. @implements IDisposable
5. @inject IShipmentService ShipmentService
6. @inject ILogger<TrackShipment> Logger
7. 
8. @if (_loading)
9. {
10.     <div class="loading-placeholder">
