12.     </div>
13. }
14. else if (_errorMessage is not null)
15. {
16.     <div class="error-message">
17.         <p>@_errorMessage</p>
18.         <button @onclick="Retry">Retry</button>
19.     </div>
20. }
21. else if (_shipment is not null)
22. {
