35.         <ul class="status-updates">
36.             @foreach (var update in _shipment.Updates)
37.             {
38.                 <li>
39.                     <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
40.                     &mdash; @update.Description
41.                 </li>
42.             }
43.         </ul>
44.     </div>
45. }
46. 
47. @code {
48.     [Parameter]
49.     public string TrackingNumber { get; set; } = default!;
50. 
51.     private ShipmentDetails? _shipment;
52.     private bool _loading;
53.     private string? _errorMessage;
54.     private CancellationTokenSource? _cts;
55. 
56.     protected override async Task OnParametersSetAsync()
57.     {
58.         await LoadShipmentAsync();
59.     }
60. 
61.     private async Task LoadShipmentAsync()
62.     {
63.         // Cancel any in-flight request
64.         _cts?.Cancel();
65.         _cts?.Dispose();
66.         _cts = new CancellationTokenSource();
67.         var ct = _cts.Token;
68. 
69.         _shipment = null;
70.         _errorMessage = null;
71.         _loading = true;
72. 
73.         try
74.         {
75.             _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
76.         }
77.         catch (OperationCanceledException) when (ct.IsCancellationRequested)
78.         {
79.             // Navigation changed or component disposed; do nothing.
80.             return;
81.         }
82.         catch (TimeoutException ex)
83.         {
84.             Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
85.             _errorMessage = "The request timed out. Please try again.";
86.         }
87.         catch (Exception ex) when (ex is not OperationCanceledException)
88.         {
89.             Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
90.             _errorMessage = "Something went wrong while loading shipment details. Please try again.";
91.         }
92.         finally
93.         {
94.             _loading = false;
95.         }
96.     }
97. 
98.     private async Task Retry()
99.     {
100.         await LoadShipmentAsync();
101.     }
102. 
103.     public void Dispose()
104.     {
105.         _cts?.Cancel();
106.         _cts?.Dispose();
107.     }
108. }
